import { useState } from "react";
import "./EMR.css";

export default function EMR() {
  const [tab, setTab] = useState("notes");

  const [patient, setPatient] = useState({
    name: "John Doe",
    age: "45",
    gender: "Male",
    mrn: "MRN-10233",
    visitId: "VIS-2026-011",
    department: "General Medicine",
    doctor: "",
  });

  const [clinical, setClinical] = useState({
    complaint: "",
    history: "",
    assessment: "",
    plan: "",
  });

  const [vitals, setVitals] = useState({
    heartRate: "",
    bpSys: "",
    bpDia: "",
    respRate: "",
    spo2: "",
    temperature: "",
    nurse: "",
  });

  return (
    <div className="emr-page">

      {/* ================= HEADER ================= */}
      <div className="emr-header">
        <div className="emr-patient">
          <img
            src="https://i.pravatar.cc/150"
            alt="patient"
          />
          <div>
            <h2>
              {patient.name} · {patient.age}Y / {patient.gender}
            </h2>
            <p>
              MRN: {patient.mrn} | Visit ID: {patient.visitId} OPD –{" "}
              {patient.department}
            </p>
          </div>
        </div>

        <button className="open-visit">OPEN VISIT</button>
      </div>

      {/* ================= TABS ================= */}
      <div className="emr-tabs">
        <button
          className={tab === "notes" ? "active" : ""}
          onClick={() => setTab("notes")}
        >
          Clinical Notes
        </button>

        <button
          className={tab === "vitals" ? "active" : ""}
          onClick={() => setTab("vitals")}
        >
          Vitals
        </button>
      </div>

      {/* ================= CLINICAL NOTES ================= */}
      {tab === "notes" && (
        <div className="emr-card">
          <label>Chief Complaint</label>
          <input
            value={clinical.complaint}
            onChange={(e) =>
              setClinical({ ...clinical, complaint: e.target.value })
            }
          />

          <label>History of Present Illness</label>
          <textarea
            value={clinical.history}
            onChange={(e) =>
              setClinical({ ...clinical, history: e.target.value })
            }
          />

          <label>Assessment</label>
          <textarea
            value={clinical.assessment}
            onChange={(e) =>
              setClinical({ ...clinical, assessment: e.target.value })
            }
          />

          <label>Plan</label>
          <textarea
            value={clinical.plan}
            onChange={(e) =>
              setClinical({ ...clinical, plan: e.target.value })
            }
          />
        </div>
      )}

      {/* ================= VITALS ================= */}
      {tab === "vitals" && (
        <div className="emr-card">
          <h3>Vital Signs</h3>

          <div className="vital-grid">
            <input
              placeholder="Heart Rate (bpm)"
              value={vitals.heartRate}
              onChange={(e) =>
                setVitals({ ...vitals, heartRate: e.target.value })
              }
            />

            <input
              placeholder="BP Systolic"
              value={vitals.bpSys}
              onChange={(e) =>
                setVitals({ ...vitals, bpSys: e.target.value })
              }
            />

            <input
              placeholder="BP Diastolic"
              value={vitals.bpDia}
              onChange={(e) =>
                setVitals({ ...vitals, bpDia: e.target.value })
              }
            />

            <input
              placeholder="Respiratory Rate"
              value={vitals.respRate}
              onChange={(e) =>
                setVitals({ ...vitals, respRate: e.target.value })
              }
            />

            <input
              placeholder="SpO₂ (%)"
              value={vitals.spo2}
              onChange={(e) =>
                setVitals({ ...vitals, spo2: e.target.value })
              }
            />

            <input
              placeholder="Temperature (°C)"
              value={vitals.temperature}
              onChange={(e) =>
                setVitals({ ...vitals, temperature: e.target.value })
              }
            />
          </div>

          <label>Nurse Name</label>
          <input
            placeholder="Enter nurse name"
            value={vitals.nurse}
            onChange={(e) =>
              setVitals({ ...vitals, nurse: e.target.value })
            }
          />
        </div>
      )}

      {/* ================= ACTIONS ================= */}
      <div className="emr-actions">
        <button className="draft">Save Draft</button>
        <button className="complete">Complete Visit</button>
      </div>
    </div>
  );
}
